import React, { useState } from 'react';
import axios from 'axios';
import IndividualAnalysis from './IndividualAnalysis';
import BatchAnalysis from './BatchAnalysis';
import Navbar from './Navbar';
import './App.css';

const API_BASE = 'http://localhost:5000/api';

function App() {
  const [mode, setMode] = useState('individual');
  const [loading, setLoading] = useState(false);
  const [results, setResults] = useState(null);
  const [batchResults, setBatchResults] = useState(null);

  const [customerData, setCustomerData] = useState({
    Tenure: 5.0,
    OrderCount: 5.0,
    CashbackAmount: 12000.0,
    DaySinceLastOrder: 7.0,
    HourSpendOnApp: 30.0,
    OrderAmountHikeFromlastYear: 15.0,
    CouponUsed: 1,
    NumberOfDeviceRegistered: 3,
    Complain: 0,
    SatisfactionScore: 3,
    WarehouseToHome: 10.0,
    NumberOfAddress: 4,
    CityTier: 1,
    PreferredLoginDevice: 'Mobile Phone',
    PreferredPaymentMode: 'Credit Card',
    PreferedOrderCat: 'Laptop & Accessory',
    Gender: 'Male',
    MaritalStatus: 'Married'
  });

  const [batchFile, setBatchFile] = useState(null);

  // Individual Analysis handler (mock)
  const handleIndividualAnalyze = async () => {
    setLoading(true);
    try {
      const response = await axios.post(`${API_BASE}/individual`, customerData);
      setResults(response.data);
    } catch (error) {
      console.error('Error analyzing data:', error);
    } finally {
      setLoading(false);
    }
  };

  // Batch Analysis handler (mock)
  const handleBatchAnalyze = async () => {
    if (!batchFile) return;
    setLoading(true);
    const formData = new FormData();
    formData.append('file', batchFile);
    try {
      const response = await axios.post(`${API_BASE}/batch`, formData);
      setBatchResults(response.data);
    } catch (error) {
      console.error('Error uploading batch:', error);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="app-container">
      {/* Professional Horizontal Navbar */}
      <Navbar mode={mode} setMode={setMode} />

      {/* Executive Header */}
      <header className="executive-header">
        <div className="header-content">
          <h1 className="header-title">Executive Churn Intelligence Platform</h1>
          <p className="header-subtitle">
            Unified predictive insights — action-first, financialized, and presentation-ready
          </p>
        </div>
      </header>

      {/* Main Content Area */}
      <main className="main-dashboard">
        <div className="dashboard-content">
          {mode === 'individual' ? (
            <IndividualAnalysis
              customerData={customerData}
              onInputChange={setCustomerData}
              onAnalyze={handleIndividualAnalyze}
              loading={loading}
              results={results}
            />
          ) : (
            <BatchAnalysis
              onFileChange={(e) => setBatchFile(e.target.files[0])}
              onAnalyze={handleBatchAnalyze}
              loading={loading}
              results={batchResults}
            />
          )}
        </div>
      </main>
    </div>
  );
}

export default App;
